from dataclasses import dataclass, field
from typing import Optional
import hashlib

@dataclass
class FeatureFlag:
    name: str
    enabled: bool = False
    rollout_pct: float = 0.0       # 0.0 – 100.0
    allowlist: list[str] = field(default_factory=list)   # user IDs always enabled
    blocklist: list[str] = field(default_factory=list)   # user IDs always disabled

    def is_enabled_for(self, user_id: str) -> bool:
        if not self.enabled:
            return False
        if user_id in self.blocklist:
            return False
        if user_id in self.allowlist:
            return True
        # Deterministic bucketing: same user always gets same experience
        bucket = int(hashlib.md5(f"{self.name}:{user_id}".encode()).hexdigest(), 16) % 100
        return bucket < self.rollout_pct

class FeatureFlagRegistry:
    def __init__(self):
        self._flags: dict[str, FeatureFlag] = {}

    def register(self, flag: FeatureFlag) -> None:
        self._flags[flag.name] = flag

    def check(self, name: str, user_id: str) -> bool:
        flag = self._flags.get(name)
        return flag.is_enabled_for(user_id) if flag else False

    def kill_switch(self, name: str) -> None:
        """Immediately disable a flag globally — use in incident response.""\"
        if name in self._flags:
            self._flags[name].enabled = False
